#include <stdio.h>
#include <string.h>

int main() {
    int K, N;
    if (scanf("%d %d", &K, &N) != 2) return 0;
    char fav[55][55];
    for (int i = 0; i < K; ++i) {
        scanf("%s", fav[i]);
    }
    char s[55];
    for (int i = 0; i < N; ++i) {
        scanf("%s", s);
        int len = strlen(s);
        int good = (len >= 47);
        if (!good) {
            for (int j = 0; j < K && !good; ++j) {
                if (strstr(s, fav[j]) != NULL) good = 1;
            }
        }
        puts(good ? "Good" : "Bad");
    }
    return 0;
}

