    if (!(cin >> K >> N)) return 0;
    vector<string> fav(K);
    for (int i = 0; i < K; ++i) cin >> fav[i];
    for (int i = 0; i < N; ++i) {
        string s; cin >> s;
        bool good = (int)s.size() >= 47;
        if (!good) {
            for (const string &f : fav) {
                if (s.find(f) != string::npos) { good = true; break; }
            }
        }
        cout << (good ? "Good" : "Bad") << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int K = Integer.parseInt(st.nextToken());
        int N = Integer.parseInt(st.nextToken());
        String[] fav = new String[K];
        for (int i = 0; i < K; ++i) fav[i] = br.readLine().trim();
        StringBuilder out = new StringBuilder();
        for (int i = 0; i < N; ++i) {
            String s = br.readLine().trim();
            boolean good = s.length() >= 47;
            if (!good) {
                for (String f : fav) {
                    if (s.contains(f)) { good = true; break; }
                }
            }
            out.append(good ? "Good" : "Bad").append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    K = int(next(it))
    N = int(next(it))
    fav = [next(it) for _ in range(K)]
    out_lines = []
    for _ in range(N):
        s = next(it)
        good = len(s) >= 47
        if not good:
            for f in fav:
                if f in s:
                    good = True
                    break
        out_lines.append('Good' if good else 'Bad')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

